import{_ as n}from"./plugin-vue_export-helper-c27b6911.js";import{o as s,c as a,e}from"./app-8181ed57.js";const p={},t=e(`<p>在并发编程中，经常会遇到多个线程访问同一个共享资源而这时候/我们就需要保证数据的“致性，那么就要用到锁的概念，给资源加上锁，拿到锁所有权的人才能够进行操作共享资源，没有拿到资源的线程需要等待，等其他线程使用完，释放锁。</p><p>在项目中，遇到多个用户抢购商品时、商品的数量就是共享资源。因此，在操作商品库存数据时，也需要使用锁保证商品库存的一致。</p><h1 id="线程锁" tabindex="-1"><a class="header-anchor" href="#线程锁" aria-hidden="true">#</a> 线程锁</h1><p>如果在单服务器架构中，就可以使用线程锁保证数据的一致性。但是，此种方案不适合多服务器架构。</p><p>假设服务器1上使用线程锁保证同一时刻只有1个用户操作数据，却无法保证其他服务器上同时不能有用户操作，仍然会产生资源竞争。</p><p>因此，在多服务器架构中，不能使用线程锁的机制。</p><h1 id="分布式锁" tabindex="-1"><a class="header-anchor" href="#分布式锁" aria-hidden="true">#</a> 分布式锁</h1><p>在上面的情况中，锁是分布在每个服务器上的。因此，不能保证所有服务器间数据的一致性。</p><p>想一想，可以将锁独立于各个服务器之外吗？</p><p>答案是肯定的，这就是分布式锁。</p><p>当确定了不同节点服务器之间需要分布式锁，那么我们就需要确定分布式锁到底有哪些功能？</p><p>互斥性：和本地锁一样，互斥性是最基本的，但是分布式锁需要保证在不同节点不同线程的互斥。</p><p>可重入性：同一个节点同一个线程如果获取了锁之后，那么也可以再次获取这个锁。</p><p>锁超时：和本地锁一样，支持锁超时，防止死锁。</p><p>高效、高可用：加锁和解锁需要高效，同时也需要保证高可用，防止分布式锁失效。</p><p>常见的分布式锁实现方式：<code>MySQL</code>、<code>Redis</code>等</p><h2 id="mysql锁" tabindex="-1"><a class="header-anchor" href="#mysql锁" aria-hidden="true">#</a> <code>MySQL</code>锁</h2><p>通过<code>MySQL</code>实现分布式锁，有两种方式：悲观锁和乐观锁。</p><h3 id="悲观锁" tabindex="-1"><a class="header-anchor" href="#悲观锁" aria-hidden="true">#</a> 悲观锁</h3><h4 id="概念" tabindex="-1"><a class="header-anchor" href="#概念" aria-hidden="true">#</a> 概念</h4><p>悲观锁是基于一种悲观的态度来防止一切数据冲突。它是以一种预防的姿态在修改数据之前把数据锁住，然后再对数据读写，在它释放锁之前，其他任何人不能对数据操作，直到前一个人把锁释放后，下一个人才对数据进行加锁，然后进行数据操作。</p><p>一般的关系型数据库管理系统中，锁的机制都是基于悲观锁的机制实现的。</p><p>特点：可以完全保证数据的独占性和正确性，因为每次请求都会对数据进行加锁，然后进行数据操作，最后再解锁，而加锁解锁的过程会造成服务器性能消耗。因此，在高并发的情况下，用<code>MySQL</code>实现分布式锁，毫无疑问是不行的！！！</p><p>只是了解<code>MySQL</code>实现分布式锁的思想即可。</p><h4 id="自定义锁表实现" tabindex="-1"><a class="header-anchor" href="#自定义锁表实现" aria-hidden="true">#</a> 自定义锁表实现</h4><p>首先，需要创建一个有关资源的锁记录表：</p><div class="language-mysql line-numbers-mode" data-ext="mysql"><pre class="language-mysql"><code>CREATE TABLE resourceLock(
    id INT UNSIGNED PRIMARY KEY AUTO_NCREMENT,
    resource_name VARCHAR(128) NOT NULL UNIQUE DEFAULT &#39;&#39; COMMENT &#39;资源名字&#39;，
    node_info VARCHAR(128) DEFAULT NUUL COMMENT &#39;机器信息&#39;,
    count INT UNSIGNED NOT NULL DEFAULT O COMMENT &#39;锁的次数，实现重入性&#39;,
    desc_info VARCHAR(128) DEFAULT NULL COMMENT &#39;额外的信息&#39;,
    update_time TIMESTAMP DEFAULT NULL COMMENT&#39;更新时间&#39;,
    create_time TIMESTAMP DEFAULT NULL COMMENT &#39;创建时间&#39;
)ENGINE=INNODB DEFAULT CHARSET=utf8;
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>定义锁的工具类</p><div class="language-python line-numbers-mode" data-ext="py"><pre class="language-python"><code><span class="token keyword">import</span> time
<span class="token keyword">from</span> django<span class="token punctuation">.</span>db <span class="token keyword">import</span> connection<span class="token punctuation">,</span> transaction


<span class="token keyword">class</span> <span class="token class-name">MysqlLock</span><span class="token punctuation">(</span><span class="token builtin">object</span><span class="token punctuation">)</span><span class="token punctuation">:</span>
    <span class="token keyword">def</span> <span class="token function">lock</span><span class="token punctuation">(</span>self<span class="token punctuation">,</span> resource<span class="token punctuation">,</span> node_info<span class="token punctuation">,</span> block<span class="token operator">=</span><span class="token boolean">False</span><span class="token punctuation">,</span> timeout<span class="token operator">=</span><span class="token number">10</span><span class="token punctuation">)</span><span class="token punctuation">:</span>
        <span class="token triple-quoted-string string">&quot;&quot;&quot;
        默认非阻塞实现
        :param resource: 需要加锁的资源名称
        :param node_info: 当前线程的身份信息
        :param block: 是否阻塞等待加锁
        :param timeout: 超时时间
        :return: True 或 False
        1.先开启事务
        2.根据参数block,决定是否阻塞等待锁的获取,即使阻塞等待,超时仍然会退出
        3.查询表中,是否已经存在有关该资源的锁记录
        4.假设已经存在锁,判断是否为当前线程添加: 是,就把锁记录加1,返回Teue；不是,返回False
        5.假设不存在锁,添加锁记录,但是,资源名称唯一,表中进没有强制开锁,因此有失败的可能。所以,成动,返回True,失败,返回False
        &quot;&quot;&quot;</span>
        <span class="token keyword">pass</span>
        <span class="token keyword">with</span> connection<span class="token punctuation">.</span>cursor<span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token keyword">as</span> cursor<span class="token punctuation">:</span>
            start <span class="token operator">=</span> time<span class="token punctuation">.</span>time<span class="token punctuation">(</span><span class="token punctuation">)</span>
            n <span class="token operator">=</span> <span class="token number">1</span>
            <span class="token keyword">while</span> n<span class="token punctuation">:</span>
                n <span class="token operator">=</span> <span class="token number">1</span> <span class="token keyword">if</span> block <span class="token keyword">else</span> <span class="token number">0</span>
                now <span class="token operator">=</span> time<span class="token punctuation">.</span>time<span class="token punctuation">(</span><span class="token punctuation">)</span>
                <span class="token keyword">if</span> now<span class="token operator">-</span>start <span class="token operator">&gt;</span> timeout<span class="token punctuation">:</span>
                    <span class="token keyword">return</span> <span class="token boolean">False</span>
                cursor<span class="token punctuation">.</span>execute<span class="token punctuation">(</span>
                    <span class="token string">&#39;select id,node_info,count from resourceLock where resource_name=%s&#39;</span><span class="token punctuation">,</span> <span class="token punctuation">[</span>resource<span class="token punctuation">]</span><span class="token punctuation">)</span>
                row <span class="token operator">=</span> cursor<span class="token punctuation">.</span>fetchone<span class="token punctuation">(</span><span class="token punctuation">)</span>
                <span class="token keyword">if</span> row<span class="token punctuation">:</span>
                    idi<span class="token punctuation">,</span> node_infol<span class="token punctuation">,</span> count1 <span class="token operator">=</span> row
                    <span class="token keyword">if</span> node_info <span class="token operator">==</span> node_infol<span class="token punctuation">:</span>
                        cursor<span class="token punctuation">.</span>execute<span class="token punctuation">(</span>
                            <span class="token string">&#39;update resourceLock set count=%s&#39;</span><span class="token punctuation">,</span> <span class="token punctuation">[</span>count1 <span class="token operator">+</span> <span class="token number">1</span><span class="token punctuation">]</span><span class="token punctuation">)</span>
                        <span class="token keyword">return</span> <span class="token boolean">True</span>
                    <span class="token keyword">elif</span> block <span class="token keyword">is</span> <span class="token boolean">False</span><span class="token punctuation">:</span>
                        <span class="token keyword">return</span> <span class="token boolean">False</span>
                <span class="token keyword">else</span><span class="token punctuation">:</span>
                    <span class="token keyword">try</span><span class="token punctuation">:</span>
                        cursor<span class="token punctuation">.</span>execute<span class="token punctuation">(</span><span class="token string">&#39;insert into resourceLock values(0,%s,%s,%s,1,&#39;</span><span class="token string">&#39;, %s,%s)&#39;</span><span class="token punctuation">,</span> <span class="token punctuation">[</span>
                                       resource<span class="token punctuation">,</span> node_info<span class="token punctuation">,</span> now<span class="token punctuation">,</span> now<span class="token punctuation">]</span><span class="token punctuation">)</span>
                    <span class="token keyword">except</span><span class="token punctuation">:</span>
                        <span class="token keyword">if</span> block <span class="token keyword">is</span> <span class="token boolean">False</span><span class="token punctuation">:</span>
                            <span class="token keyword">return</span> <span class="token boolean">False</span>
                    <span class="token keyword">return</span> <span class="token boolean">True</span>

    <span class="token keyword">def</span> <span class="token function">unlock</span><span class="token punctuation">(</span>self<span class="token punctuation">,</span> resource<span class="token punctuation">,</span> node_info<span class="token punctuation">)</span><span class="token punctuation">:</span>
        <span class="token triple-quoted-string string">&quot;&quot;&quot;
        释放锁
        :param resource:要加锁的资源名称
        :param node_info:当前线程的身份信息
        :return:True或False
        1.先开启事务
        2.查询表中,是否已经存在当前线程有关该资源的锁记录
        3.假设存在锁记录,如果次数大于1,就更新次数减1,否则,删除该条记录,最后返回True
        4.假设不存在所记录,则返回False
        &quot;&quot;&quot;</span>
        <span class="token keyword">with</span> connection<span class="token punctuation">.</span>cursor<span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token keyword">as</span> cursor<span class="token punctuation">:</span>
            <span class="token keyword">with</span> transaction<span class="token punctuation">.</span>atomic<span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">:</span>
                cursor<span class="token punctuation">.</span>execute<span class="token punctuation">(</span><span class="token string">&#39;select id,node_info,count from resourceLock where resource_name=%s and node_info=%s&#39;</span><span class="token punctuation">,</span><span class="token punctuation">[</span>resource<span class="token punctuation">,</span> node_info<span class="token punctuation">]</span><span class="token punctuation">)</span>
                row <span class="token operator">=</span> cursor<span class="token punctuation">.</span>fetchone<span class="token punctuation">(</span><span class="token punctuation">)</span>
                <span class="token keyword">if</span> <span class="token keyword">not</span> row<span class="token punctuation">:</span>
                    <span class="token keyword">return</span> <span class="token boolean">False</span>
                id1<span class="token punctuation">,</span> node_infol<span class="token punctuation">,</span> count1 <span class="token operator">=</span> row
                <span class="token keyword">if</span> count1 <span class="token operator">&gt;</span> <span class="token number">1</span><span class="token punctuation">:</span>
                    cursor<span class="token punctuation">.</span>execute<span class="token punctuation">(</span>
                        <span class="token string">&#39;update resourceLock set count=%s&#39;</span><span class="token punctuation">,</span> <span class="token punctuation">[</span>count1<span class="token operator">-</span><span class="token number">1</span><span class="token punctuation">]</span><span class="token punctuation">)</span>
                <span class="token keyword">else</span><span class="token punctuation">:</span>
                    cursor<span class="token punctuation">.</span>execute<span class="token punctuation">(</span><span class="token string">&#39;delete from resourceLock where resource_name=%s and node_info=%s&#39;</span><span class="token punctuation">,</span><span class="token punctuation">[</span>resource<span class="token punctuation">,</span> node_info<span class="token punctuation">]</span><span class="token punctuation">)</span>
                <span class="token keyword">return</span> <span class="token boolean">True</span>

</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>每次操作资源之前，进行加锁，加锁成功，继续操作；否则，就不操作；操作成功，释放锁。</p><p>上面这种实现有以下几个问题：</p><ul><li>这把锁高度依赖数据库的可用性，数据库是个单点，一旦挂掉，会导致业务系统不可用</li><li>这把锁没有关闭时间，一旦解锁操作失败，就会导致锁记录一直存在数据库中，其他线程无法再获取锁</li></ul><p>针对上面的问题，可以对症下药：</p><ul><li>数据库是单点？实现数据库之间的主从同步，一个<code>MySQL</code>服务挂掉，立即切换到从机</li><li>没有失效时间？实现一个定时服务，每隔一定时间把数据库中的超时数据清理掉</li></ul><h4 id="mysql行锁实现" tabindex="-1"><a class="header-anchor" href="#mysql行锁实现" aria-hidden="true">#</a> <code>MySQL</code>行锁实现</h4><p>开启事务；<br> 开启需要操作的<code>MySQL</code>表记录的行锁，防止其他操作干扰；</p><p>操作完成，提交事务；</p><p>假设需要更新商品id为3的库存减一</p><p><code>SQL</code>语句实现：</p><div class="language-mysql line-numbers-mode" data-ext="mysql"><pre class="language-mysql"><code>begin; # 开启事务
select count from tb_goods where id=3 for update; # 查询库存为20，并开启行锁
update tb_goods set count=19 where id=3; # 设置库存减一
commit; # 提交事务
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><code>Django</code>实现：</p><div class="language-python line-numbers-mode" data-ext="py"><pre class="language-python"><code><span class="token keyword">with</span> transaction<span class="token punctuation">.</span>atomicC<span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">:</span>
    <span class="token keyword">try</span><span class="token punctuation">:</span>
        goods <span class="token operator">=</span> Goods<span class="token punctuation">.</span>objects<span class="token punctuation">.</span>select_for_update<span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">.</span>get<span class="token punctuation">(</span><span class="token builtin">id</span><span class="token operator">=</span><span class="token number">3</span><span class="token punctuation">)</span> <span class="token comment"># 开启行锁</span>
    <span class="token keyword">except</span><span class="token punctuation">:</span>
        transaction<span class="token punctuation">.</span>rollback<span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token comment"># 失败，进行回滚</span>
    goods<span class="token punctuation">.</span>count <span class="token operator">-=</span> <span class="token number">1</span> <span class="token comment"># 修改库存</span>
    goods<span class="token punctuation">.</span>save<span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token comment"># 保存库</span>
    transaction<span class="token punctuation">.</span>commit<span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token comment"># 提交事务</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="乐观锁" tabindex="-1"><a class="header-anchor" href="#乐观锁" aria-hidden="true">#</a> 乐观锁</h3><p>所谓的乐观锁；是对数据冲突保持 种乐观态度，假设数据一般情况下，不会产生冲突。所以，在操作数据时不会对操作的数据进行加锁（这使得多个任务可以并行得对数据进行操作），只有在数据提交时，才通过一种机制对数据的冲突与否进行检测。如果，发现数据冲突了；则返回错误信息，让用户决定如何去做。</p><p>特点：乐观锁是一种并发型的锁，本身不对数据进行加锁，而是通过业务实现锁的功能。不对数据加锁就意味着允许多个请求同时访问数据，同时也省掉了对数据加锁、解锁过程，所以在一定程度下会提高性能。不过在高并发情况下，会导致大量的请求冲突，冲突会导致大部分操作无功而返，浪费系统资源。所以，在高并发情况下，乐观锁性能反而不如悲观锁。</p><p><code>SQL</code>语句实现：</p><div class="language-mysql line-numbers-mode" data-ext="mysql"><pre class="language-mysql"><code>select id, count, version from tb_goods where id=3; # 在商品表中多一个数据的版本号version，查询库存为20，版本号为27
update tb_goods set count=19,version=28 where id=3 and version=27; # 将库存减1，版本号加1
# 如果更新成功，说明没有其他线程抢占资源，否则，说明资源已经被抢占，需要重新再来。
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><code>Django</code>实现：</p><div class="language-python line-numbers-mode" data-ext="py"><pre class="language-python"><code><span class="token keyword">try</span><span class="token punctuation">:</span>
    goods <span class="token operator">=</span> Goads<span class="token punctuation">.</span>objects<span class="token punctuation">.</span>get<span class="token punctuation">(</span><span class="token builtin">id</span><span class="token operator">=</span><span class="token number">3</span><span class="token punctuation">)</span> <span class="token comment"># 开启行锁</span>
<span class="token keyword">except</span><span class="token punctuation">:</span>
    <span class="token keyword">pass</span> 
Goods<span class="token punctuation">.</span>objects<span class="token punctuation">.</span><span class="token builtin">filter</span><span class="token punctuation">(</span><span class="token builtin">id</span><span class="token operator">=</span><span class="token number">3</span><span class="token punctuation">,</span> version<span class="token operator">=</span>goods<span class="token punctuation">.</span>version<span class="token punctuation">)</span><span class="token punctuation">.</span>update<span class="token punctuation">(</span>count<span class="token operator">=</span>goods<span class="token punctuation">.</span>count<span class="token operator">+</span><span class="token number">1</span><span class="token punctuation">)</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="redis锁" tabindex="-1"><a class="header-anchor" href="#redis锁" aria-hidden="true">#</a> <code>Redis</code>锁</h2><p><code>Redis</code>实现分布式锁原理是：一个线程在<code>redis</code>中存入一个value，其他线程也要存的时候，发现key已经有value，就只好放弃或稍后再试。</p><p>一般使用的命令是：<code>setnx</code>或<code>set</code> 加<code>nx</code>参数，只允许一个客户端添加数据，先到先得；再调用<code>del</code>删除数据，释放资源。</p><h3 id="加锁" tabindex="-1"><a class="header-anchor" href="#加锁" aria-hidden="true">#</a> 加锁</h3><p>加锁的过程实际就是在redis中，给key设置个value。</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token number">106.128</span>.28.10:<span class="token operator"><span class="token file-descriptor important">0</span>&gt;</span>keys *  <span class="token comment"># redis中不存在数据</span>
<span class="token number">106.128</span>.28.10:<span class="token operator"><span class="token file-descriptor important">0</span>&gt;</span>setnx <span class="token string">&#39;tb_goods&#39;</span> <span class="token number">1</span>  <span class="token comment"># 将商品有关的标志存入redis</span>
<span class="token string">&quot;1&quot;</span>
<span class="token number">106.128</span>.28.10：<span class="token operator"><span class="token file-descriptor important">0</span>&gt;</span>setnx <span class="token string">&#39;tb_goods&#39;</span> <span class="token number">1</span> <span class="token comment"># 其他客户端再存，就无法存入</span>
<span class="token string">&quot;0&quot;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>但是，此时存在一个问题，就是服务器1设置锁之后，突然挂掉，无法删除锁；同时其他服务器一直无法获取，导致死锁，怎么办？</p><p>很简单，设置过期时间。</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token number">106.128</span>.28.10:<span class="token operator"><span class="token file-descriptor important">0</span>&gt;</span>setnx <span class="token string">&#39;tb_goods&#39;</span> <span class="token number">1</span>  <span class="token comment"># 先存</span>
<span class="token string">&quot;1&quot;</span>
<span class="token number">106.128</span>.28.10：<span class="token operator"><span class="token file-descriptor important">0</span>&gt;</span>EXPIRE <span class="token string">&#39;tb goods&#39;</span> <span class="token number">10</span>  <span class="token comment"># 后设置过期时间</span>
<span class="token string">&quot;1&quot;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>这种情况下，仍然会出现问题，因为不是一步操作，不具备原子性，可能会出现：第一步执行完，服务器挂掉，并没有执行第二步，此时，有两种操作方案可以解决这个问题：使用lua脚本或使用set指令。</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token number">106.128</span>.28.10:<span class="token operator"><span class="token file-descriptor important">0</span>&gt;</span>keys *

<span class="token number">106.228</span>.28.10:<span class="token operator"><span class="token file-descriptor important">0</span>&gt;</span>set <span class="token string">&#39;tb_goods&#39;</span> <span class="token number">1</span> ex <span class="token number">10</span> nx  <span class="token comment"># 此时就是原子操作，在设置值同时还设置过期时间</span>
<span class="token string">&quot;OK&quot;</span>
<span class="token number">106.128</span>.28.10:<span class="token operator"><span class="token file-descriptor important">0</span>&gt;</span>keys *
<span class="token number">1</span><span class="token punctuation">)</span> <span class="token string">&quot;tb_goods&quot;</span>
<span class="token number">106.128</span>.28.10:<span class="token operator"><span class="token file-descriptor important">0</span>&gt;</span>set <span class="token string">&#39;tb_goods&#39;</span> <span class="token number">1</span> ex <span class="token number">10</span> nx 
null
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="解锁" tabindex="-1"><a class="header-anchor" href="#解锁" aria-hidden="true">#</a> 解锁</h3><p>解锁的过程实际就是将key键删除。</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token number">106.128</span>.28.10:<span class="token operator"><span class="token file-descriptor important">0</span>&gt;</span>del <span class="token string">&#39;tb_goods&#39;</span>
<span class="token string">&quot;1&quot;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><p>注意：删除键的过程中不能乱删，也就是自己只能释放自己的锁，不允许释放别人的锁。</p><p>有人会有疑惑：在多线程场景中，线程A获取到锁，但如果A不释放锁，此时，线程B是获取不到的，怎么会释放别人的锁？</p><p>假设线程A和B都用同一个键加锁。线程A加锁成功，由于业务时间过长，超过了设置的超时时间。这时，redis会释放锁。此时，线程B就可以加锁成功，然后执行业务操作。恰巧，此时A执行完业务逻辑，删除键释放锁。此时，就会出现线程A删除线程B的锁。</p><p>如何解决这个问题呢？在set命令加锁时，value可以使用随机数，删除时，先判断是否相等，再删除。</p><p>因为这两步操作在redis中是分开执行的，所以，需要通过lua脚本，实现原子操作。</p><div class="language-lua line-numbers-mode" data-ext="lua"><pre class="language-lua"><code><span class="token keyword">if</span> redis<span class="token punctuation">.</span><span class="token function">call</span><span class="token punctuation">(</span><span class="token string">&#39;get&#39;</span>，KEYS<span class="token punctuation">[</span><span class="token number">1</span><span class="token punctuation">]</span><span class="token punctuation">)</span> <span class="token operator">==</span> ARGV<span class="token punctuation">[</span><span class="token number">1</span><span class="token punctuation">]</span> <span class="token keyword">then</span> 
    <span class="token keyword">return</span> redis<span class="token punctuation">.</span><span class="token function">call</span><span class="token punctuation">(</span><span class="token string">&#39;del&#39;</span><span class="token punctuation">,</span> KEYS<span class="token punctuation">[</span><span class="token number">1</span><span class="token punctuation">]</span><span class="token punctuation">)</span>
<span class="token keyword">else</span> 
    <span class="token keyword">return</span> <span class="token number">0</span>
<span class="token keyword">end</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>上面的代码解决了释放其他人的锁的问题。但是还是没有解决 锁超时的问题，怎么办呢？给锁续命</p><ul><li><p>到了超时时间，如果业务代码还没有执行完成，需要给锁自动续期。</p></li><li><p>获取锁之后，自动开启一个定时任务，每个10s，自动刷新一次过期时间。</p></li></ul><p>当然，还有锁竞争问题、锁重入问题、主从复制问题等，之后再说吧。</p>`,72),o=[t];function c(i,l){return s(),a("div",null,o)}const d=n(p,[["render",c],["__file","分布式锁-4eb3381c.html.vue"]]);export{d as default};
